def cosine(a, b):
    shared = set(a) & set(b)
    na = sum(v * v for v in a.values())
    nb = sum(v * v for v in b.values())
    if na == 0 or nb == 0:
        return 0.0
    dot = sum(a[k] * b[k] for k in shared)
    return dot / (na ** 0.5 * nb ** 0.5)

