import heapq

def kth_largest_simple(nums, k):
    return heapq.nlargest(k, nums)[-1]

def kth_largest_heap(nums, k):
    h = []
    for n in nums:
        heapq.heappush(h, n)
        if len(h) > k:
            heapq.heappop(h)     # drop the smallest so far
    return h[0]                  # root = kth largest

